// normaliza un nombre escrito por el docente → clave del catálogo (o null)
function normalizar(n) {
  return String(n || '').trim().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}
export function buscarPersonaje(nombre) {
  const n = normalizar(nombre);
  if (!n || n === 'gato' || n === 'cat') return 'gato';
  for (const [clave, p] of Object.entries(PERSONAJES)) {
    if (clave === n || p.aliases.some(a => normalizar(a) === n) || normalizar(p.nombre) === n) return clave;
  }
  return null;
}
export function buscarFondo(nombre) {
  const n = normalizar(nombre);
  for (const [clave, f] of Object.entries(FONDOS)) {
    if (clave === n || f.aliases.some(a => normalizar(a) === n) || normalizar(f.nombre) === n) return clave;
  }
  return null;
}
export function listaNombresPersonajes() {
  return ['Gato'].concat(Object.values(PERSONAJES).map(p => p.nombre));
}
export function listaNombresFondos() {
  return Object.values(FONDOS).map(f => f.nombre);
}
